use std::{env, fs, process};fn main() {    let args: Vec<String> = env::args().collect();    if args.len() < 3 {        print_usage();        process::exit(1);    }    let command = &args[1];    let path = &args[2];    let source = match fs::read_to_string(path) {        Ok(content) => content,        Err(err) => {            eprintln!("Failed to read '{}': {}", path, err);            process::exit(1);        }    };    match command.as_str() {        "check" => match pulsec_core::check(&source) {            Ok(program) => {                println!(                    "OK: package={} imports={} classes={}",                    program.package.name,                    program.imports.len(),                    program.classes.len()                );            }            Err(err) => {                eprintln!("Compile error: {}", err);                process::exit(1);            }        },        "build" => {            println!("Build pipeline not implemented yet.");            println!("Use 'check' for now.");        }        _ => {            print_usage();            process::exit(1);        }    }}fn print_usage() {    eprintln!("Usage: pulsec <check|build> <file.pulse>");}